mapper.select:
SELECT c.id AS cart_id, c.shop_id, c.product_id, p.name AS product_name, p.image_url AS product_image_url, p.status AS product_status, p.stock AS product_stock, CASE WHEN p.id IS NOT NULL AND p.deleted = 0 THEN 1 ELSE 0 END AS product_exists, CASE WHEN cat.id IS NOT NULL AND cat.deleted = 0 AND cat.status = 1 THEN 1 ELSE 0 END AS category_available, NULLIF(c.specification_id, 0) AS specification_id, ps.name AS specification_name, CASE WHEN (c.specification_id = 0 AND NOT EXISTS ( SELECT 1 FROM product_specification active_ps WHERE active_ps.product_id = c.product_id AND active_ps.deleted = 0 AND active_ps.status = 1 )) OR (ps.id IS NOT NULL AND ps.deleted = 0 AND ps.status = 1) THEN 1 ELSE 0 END AS specification_valid, NULLIF(c.taste_id, 0) AS taste_id, pt.name AS taste_name, CASE WHEN c.taste_id = 0 OR (pt.id IS NOT NULL AND pt.deleted = 0 AND pt.status = 1) THEN 1 ELSE 0 END AS taste_valid, COALESCE(p.price, 0.00) + COALESCE(ps.price_delta, 0.00) AS unit_price, c.quantity FROM shopping_cart c LEFT JOIN product p ON p.id = c.product_id AND p.shop_id = c.shop_id LEFT JOIN category cat ON cat.id = p.category_id AND cat.shop_id = p.shop_id LEFT JOIN product_specification ps ON ps.id = c.specification_id AND ps.product_id = c.product_id LEFT JOIN product_taste pt ON pt.id = c.taste_id AND pt.product_id = c.product_id WHERE c.user_id = #{userId} AND c.id IN
#{cartItemId}
ORDER BY c.id FOR UPDATE
